// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/**
 * @title FarmToken (FTK)
 * @notice In-game utility token for the AgriTech Farm platform.
 *
 * Key mechanics
 * ─────────────
 * • Hard cap of 100 M tokens (MAX_SUPPLY).
 * • Annual release cap of 20 M tokens that resets every 365 days from
 *   the first mint / contract deployment (ANNUAL_RELEASE_CAP).
 * • Minter-role system: owner can authorise/revoke backend hot-wallets
 *   without transferring full ownership.
 * • Ownable pause: halts all transfers and minting in an emergency.
 * • Standard ERC-20 Burnable for deflationary market-fee burns.
 *
 * Annual cap rollover
 * ───────────────────
 * The annual counter resets lazily: the first mint after a year has
 * elapsed since `yearStartTimestamp` resets the counter and advances
 * the timestamp by exactly one year (so drift is deterministic).
 */
contract FarmToken is ERC20, ERC20Burnable, Ownable, Pausable {

    // ── Constants ────────────────────────────────────────────────────────

    /// @notice Absolute hard cap: 100 000 000 FTK.
    uint256 public constant MAX_SUPPLY = 100_000_000 * 10 ** 18;

    /// @notice Maximum tokens that may be minted in any single calendar year.
    uint256 public constant ANNUAL_RELEASE_CAP = 20_000_000 * 10 ** 18;

    uint256 private constant SECONDS_PER_YEAR = 365 days;

    /// @notice Maximum recipients allowed in a single batchMint call.
    uint256 public constant BATCH_MAX = 200;

    // ── State ────────────────────────────────────────────────────────────

    /// @notice Tokens minted since the start of the current year window.
    uint256 public totalMintedThisYear;

    /// @notice Unix timestamp when the current year window began.
    uint256 public yearStartTimestamp;

    /// @notice Addresses authorised to call mint / batchMint.
    mapping(address => bool) public isMinter;

    // ── Events ───────────────────────────────────────────────────────────

    /**
     * @notice Emitted on every successful mint.
     * @param to      Recipient address.
     * @param amount  Raw token amount (18 decimals).
     * @param reason  Human-readable label ("checkin", "gacha", "mission", …).
     */
    event TokenMinted(address indexed to, uint256 amount, string reason);

    /**
     * @notice Emitted when the owner grants or revokes a minter.
     * @param minter  Address affected.
     * @param status  True = granted, false = revoked.
     */
    event MinterUpdated(address indexed minter, bool status);

    // ── Custom errors ────────────────────────────────────────────────────

    error NotMinter(address caller);
    error MaxSupplyExceeded(uint256 requested, uint256 remaining);
    error AnnualCapExceeded(uint256 requested, uint256 remaining);
    error ArrayLengthMismatch(uint256 tosLen, uint256 amountsLen);
    error BatchTooLarge(uint256 length, uint256 max);
    error InvalidMinterAddress();
    error EmptyBatch();

    // ── Modifiers ────────────────────────────────────────────────────────

    modifier onlyMinter() {
        if (!isMinter[msg.sender]) revert NotMinter(msg.sender);
        _;
    }

    // ── Constructor ──────────────────────────────────────────────────────

    /**
     * @param initialOwner  Address that receives the Ownable owner role.
     *                      Should be a multisig in production.
     */
    constructor(address initialOwner)
        ERC20("Farm Token", "FTK")
        Ownable(initialOwner)
    {
        yearStartTimestamp = block.timestamp;
    }

    // ── Minting ──────────────────────────────────────────────────────────

    /**
     * @notice Mint tokens to a single recipient.
     * @dev    Enforces MAX_SUPPLY and ANNUAL_RELEASE_CAP.
     *         Emits TokenMinted with an empty reason string.
     * @param to     Recipient.
     * @param amount Token amount (18 decimals).
     */
    function mint(address to, uint256 amount) external onlyMinter whenNotPaused {
        _mintWithReason(to, amount, "");
    }

    /**
     * @notice Mint tokens with an audit reason attached to the event.
     * @param to     Recipient.
     * @param amount Token amount (18 decimals).
     * @param reason Short label, e.g. "daily_checkin", "mission_reward".
     */
    function mintWithReason(
        address to,
        uint256 amount,
        string calldata reason
    ) external onlyMinter whenNotPaused {
        _mintWithReason(to, amount, reason);
    }

    /**
     * @notice Gas-efficient batch mint for reward distributions.
     * @dev    Computes the aggregate amount first, performs a single cap
     *         check, then executes individual mints.
     *         Reverts the entire batch if any cap is breached.
     * @param tos     Array of recipient addresses.
     * @param amounts Parallel array of raw token amounts.
     */
    function batchMint(
        address[] calldata tos,
        uint256[] calldata amounts
    ) external onlyMinter whenNotPaused {
        if (tos.length == 0) revert EmptyBatch();
        if (tos.length != amounts.length)
            revert ArrayLengthMismatch(tos.length, amounts.length);
        if (tos.length > BATCH_MAX)
            revert BatchTooLarge(tos.length, BATCH_MAX);

        _rolloverYearIfNeeded();

        // Single aggregate validation — fail atomically, no partial mints.
        uint256 totalAmount;
        for (uint256 i = 0; i < amounts.length; ++i) {
            totalAmount += amounts[i];
        }
        uint256 supplyRemaining = MAX_SUPPLY - totalSupply();
        if (totalAmount > supplyRemaining)
            revert MaxSupplyExceeded(totalAmount, supplyRemaining);
        uint256 annualRemaining = ANNUAL_RELEASE_CAP - totalMintedThisYear;
        if (totalAmount > annualRemaining)
            revert AnnualCapExceeded(totalAmount, annualRemaining);

        totalMintedThisYear += totalAmount;

        for (uint256 i = 0; i < tos.length; ++i) {
            _mint(tos[i], amounts[i]);          // OZ reverts on address(0)
            emit TokenMinted(tos[i], amounts[i], "batch");
        }
    }

    // ── Minter management ────────────────────────────────────────────────

    /**
     * @notice Grant or revoke minting rights for an address.
     * @param minter  Address to update.
     * @param status  True to grant, false to revoke.
     */
    function setMinter(address minter, bool status) external onlyOwner {
        if (minter == address(0)) revert InvalidMinterAddress();
        isMinter[minter] = status;
        emit MinterUpdated(minter, status);
    }

    // ── Pause ────────────────────────────────────────────────────────────

    /// @notice Pause all token operations. Only owner.
    function pause() external onlyOwner {
        _pause();
    }

    /// @notice Unpause token operations. Only owner.
    function unpause() external onlyOwner {
        _unpause();
    }

    // ── View helpers ─────────────────────────────────────────────────────

    /// @notice Remaining FTK that may be minted in the current year window.
    function remainingAnnualCap() external view returns (uint256) {
        return ANNUAL_RELEASE_CAP - totalMintedThisYear;
    }

    /// @notice Remaining FTK until the hard supply cap.
    function remainingSupply() external view returns (uint256) {
        return MAX_SUPPLY - totalSupply();
    }

    /// @notice Unix timestamp at which the current year window closes.
    function currentYearEndsAt() external view returns (uint256) {
        return yearStartTimestamp + SECONDS_PER_YEAR;
    }

    // ── Internal ─────────────────────────────────────────────────────────

    /// @dev Core mint logic shared by mint() and mintWithReason().
    function _mintWithReason(
        address to,
        uint256 amount,
        string memory reason
    ) private {
        _rolloverYearIfNeeded();

        uint256 supplyRemaining = MAX_SUPPLY - totalSupply();
        if (amount > supplyRemaining)
            revert MaxSupplyExceeded(amount, supplyRemaining);
        uint256 annualRemaining = ANNUAL_RELEASE_CAP - totalMintedThisYear;
        if (amount > annualRemaining)
            revert AnnualCapExceeded(amount, annualRemaining);

        totalMintedThisYear += amount;
        _mint(to, amount);
        emit TokenMinted(to, amount, reason);
    }

    /**
     * @dev Roll the annual window forward if 365 days have elapsed.
     *      Advances by exactly SECONDS_PER_YEAR to avoid drift accumulation.
     */
    function _rolloverYearIfNeeded() private {
        if (block.timestamp >= yearStartTimestamp + SECONDS_PER_YEAR) {
            // May need to advance multiple years if contract was dormant.
            while (block.timestamp >= yearStartTimestamp + SECONDS_PER_YEAR) {
                yearStartTimestamp += SECONDS_PER_YEAR;
            }
            totalMintedThisYear = 0;
        }
    }

    /**
     * @dev Override ERC-20 _update to enforce pause on ALL token movements
     *      (transfers, mints, burns).  Minting is additionally gated by
     *      `whenNotPaused` on the public mint functions.
     */
    function _update(
        address from,
        address to,
        uint256 value
    ) internal override whenNotPaused {
        super._update(from, to, value);
    }
}

